import { Component, OnInit } from '@angular/core';
import { AuthService } from 'src/app/services/auth.service';
import { Router } from '@angular/router';

@Component({
  selector: 'app-perfil',
  templateUrl: './perfil.component.html',
  styleUrls: ['./perfil.component.css']
})
export class PerfilComponent implements OnInit {
  userName: string = '';
  userEmail: string = '';
  emailVerified: boolean = false; // 🔹 Corrigido para iniciar como false
  verificationMessage: string = '';

  constructor(private authService: AuthService, private router: Router) {}

  ngOnInit(): void {
    this.userName = this.authService.getUserName();
    this.userEmail = this.authService.getUserEmail();

    // Adicionar log para debugar
    console.log('Inicializando componente de perfil');

    this.authService.getUserVerificationStatus().subscribe({
      next: (response) => {
        console.log('Resposta da verificação:', response);

        if (response) {
          // Verificar diretamente a resposta
          this.emailVerified = !!response.emailVerified;

          // Garantir que temos uma mensagem, mesmo que venha vazia da API
          if (response.verificationMessage) {
            this.verificationMessage = response.verificationMessage;
          } else {
            this.verificationMessage = 'Seu e-mail ainda não foi verificado. Por favor, verifique sua caixa de entrada ou solicite um novo e-mail de verificação.';
          }

          console.log('Status do email:', this.emailVerified);
          console.log('Mensagem de verificação:', this.verificationMessage);
        }
      },
      error: (err) => {
        console.error('Erro ao buscar status de verificação:', err);
        // Definir valores padrão em caso de erro
        this.emailVerified = false;
        this.verificationMessage = 'Não foi possível verificar o status do seu email. Por favor, tente novamente mais tarde.';
      }
    });
  }

  reenviarEmailVerificacao() {
    console.log('Iniciando processo de reenvio de email...');
    this.verificationMessage = 'Enviando solicitação de verificação...';

    // Verificar se temos o email do usuário
    const userEmail = this.authService.getUserEmail();
    if (!userEmail || userEmail === 'Email não encontrado') {
      console.error('Email do usuário não disponível');
      this.verificationMessage = 'Não foi possível reenviar o email. Email do usuário não encontrado.';
      return;
    }

    console.log('Chamando serviço de reenvio para o email:', userEmail);
    this.authService.resendVerificationEmail().subscribe({
      next: (response) => {
        console.log('Resposta de sucesso:', response);
        this.verificationMessage = 'Email de verificação reenviado com sucesso! Verifique sua caixa de entrada.';

        // Atualizar o status de verificação após reenviar o email
        setTimeout(() => {
          this.authService.getUserVerificationStatus().subscribe();
        }, 1000);
      },
      error: (err) => {
        console.error('Erro completo ao reenviar e-mail:', err);

        if (err.status === 500) {
          // Como o email está sendo enviado mesmo com erro 500, vamos verificar a mensagem do erro
          if (err.error?.message?.includes('already verified')) {
            this.verificationMessage = 'Este email já foi verificado anteriormente.';
          } else {
            this.verificationMessage = 'Email de verificação enviado! Por favor, verifique sua caixa de entrada. Se não receber em alguns minutos, tente novamente.';
          }
        } else if (err.status === 404) {
          this.verificationMessage = 'Endereço de email não encontrado. Verifique se você está usando o email correto.';
        } else if (err.status === 401) {
          this.verificationMessage = 'Sua sessão expirou. Por favor, faça login novamente.';
          this.router.navigate(['/login']);
        } else {
          this.verificationMessage = `Não foi possível reenviar o email de verificação. ${err.error?.message || 'Por favor, tente novamente mais tarde.'}`;
        }
      }
    });
  }

  logout(): void {
    this.authService.logout();
    this.router.navigate(['/login']);
  }
}
